
-- ID 336
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuál es el horario de atención de la oficina de Estadías?','La oficina de Estadías e Inserción Laboral brinda atención de lunes a viernes en un horario de 9:00 a.m. a 5:00 p.m. Se recomienda acudir con anticipación y evitar llegar cerca de la hora de cierre para poder brindarte una mejor atención. Para más información, puedes comunicarte al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,
'["horario estadias","horario oficina estadias","a que hora atienden estadias","horario vinculacion","horario practicas profesionales","cuando abre estadias","cuando cierra estadias","atencion estadias horario","horario insercion laboral","oficina estadias horario","estadias horario uttt","horario departamento estadias","hora atencion estadias","horario practicas uttt","estadias telefono horario","oficina vinculacion horario","cuando puedo ir a estadias","horario servicio estadias","estadias lunes viernes","contacto estadias horario"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 337
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿En dónde está ubicada la oficina de Estadías?','La oficina del Departamento de Estadías e Inserción Laboral se encuentra en el Edificio de Vinculación. Como referencia, está ubicada cerca de los baños de mujeres dentro del edificio. Para más información, puedes comunicarte al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,
'["donde esta estadias","ubicacion oficina estadias","donde queda vinculacion","donde estan practicas profesionales","ubicacion estadias uttt","oficina estadias donde esta","como llegar a estadias","donde queda insercion laboral","edificio vinculacion donde esta","ubicacion practicas uttt","donde preguntar estadias","estadias edificio","donde esta oficina vinculacion","ubicacion departamento estadias","donde hacer tramite estadias","oficina practicas profesionales","estadias cerca baños mujeres","donde esta vinculacion uttt","ubicacion estadias universidad","donde ir para estadias"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');



-- ID 338
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿A qué teléfono o correo puedo contactar al área de Estadías?','Puedes comunicarte con el Departamento de Estadías e Inserción Laboral a través del correo practicas@uttt.edu.mx, preferentemente utilizando tu cuenta institucional. También puedes llamar al teléfono 773 732 9100 extensiones 209 o 108 para recibir apoyo e información.','alumnos',true,
