-- ID 339
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué son las estadías?','Las estadías corresponden al último cuatrimestre de tu formación académica y son completamente prácticas. Durante este periodo te integras de tiempo completo a una empresa para desarrollar un proyecto real relacionado con tu carrera profesional, adquiriendo experiencia laboral y profesional.','alumnos',true,
'["que son las estadias","estadias que significan","practicas profesionales uttt","como funcionan las estadias","que hago en estadias","estadias universidad","estadias alumnos","que es una estadia profesional","estadias explicacion","estadias uttt"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 340
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Son obligatorias las estadías?','Sí. Las estadías son un requisito obligatorio para poder titularte tanto en nivel TSU como en Ingeniería o Licenciatura.','alumnos',true,
'["estadias obligatorias","puedo no hacer estadias","estadias requisito","estadias para titularme","estadias son necesarias","puedo graduarme sin estadias","estadias obligatorias uttt","estadias requisito titulacion","hacer estadias obligatorio","estadias universidad obligatorias"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 341
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿En qué cuatrimestre me toca irme a estadías?','Depende del nivel académico que curses actualmente. En nivel TSU las estadías se realizan en 6to cuatrimestre, mientras que en Ingeniería o Licenciatura corresponden al 10mo cuatrimestre.','alumnos',true,
'["cuando me voy a estadias","cuatrimestre estadias","estadias 6to cuatrimestre","estadias 10mo cuatrimestre","cuando hago estadias","estadias ingenieria","estadias tsu","en que semestre hago estadias","estadias cuando tocan","cuatrimestre practicas profesionales"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 342
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuánto tiempo duran las estadías?','Las estadías tienen una duración de 600 horas distribuidas a lo largo del cuatrimestre correspondiente.','alumnos',true,
'["cuanto duran las estadias","horas estadias","duracion estadias","cuantas horas son estadias","estadias tiempo","estadias 600 horas","duracion practicas profesionales","cuanto tiempo son estadias","estadias cuanto duran","horas practicas profesionales"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 343
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Necesito promedio mínimo para irme a estadías?','Sí. Es indispensable cumplir con el promedio mínimo requerido para mantenerte como alumno regular y vigente antes de iniciar tu estadía.','alumnos',true,
'["promedio para estadias","promedio minimo estadias","necesito promedio estadias","estadias promedio requerido","promedio obligatorio estadias","puedo irme a estadias bajo promedio","estadias alumno regular","promedio estadias uttt","requisito promedio estadias","promedio minimo practicas"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 344
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué pasa si repruebo una materia antes de estadías?','No podrás iniciar tu estadía si tienes materias pendientes o adeudos académicos. Es necesario haber aprobado el 100% de tus materias antes de comenzar el periodo de estadía.','alumnos',true,
'["repruebo antes estadias","materias pendientes estadias","puedo irme a estadias reprobando","adeudo materias estadias","estadias materias pendientes","reprobar materia estadias","puedo hacer estadias debiendo materias","estadias requisitos materias","materias reprobadas estadias","100 creditos estadias"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 345
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Es obligatorio tener el IMSS vigente para estadías?','Sí. Es obligatorio contar con el Seguro Facultativo del IMSS vigente antes de iniciar tu estadía, ya que tanto la universidad como la empresa lo requieren por motivos de seguridad y protección del estudiante. Si necesitas apoyo para revisar tu vigencia, puedes acudir al área de Servicio Médico de la universidad.','alumnos',true,
'["imss estadias","seguro facultativo estadias","necesito imss para estadias","imss obligatorio estadias","vigencia imss estadias","seguro para practicas profesionales","estadias seguro facultativo","como revisar imss estadias","imss vigente universidad","seguro estudiante estadias"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 346
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Puedo hacer mi estadía en cualquier empresa o necesita convenio?','No es obligatorio que la empresa tenga convenio previo con la universidad. Puedes realizar tu estadía en una empresa que se relacione con tu perfil profesional y objetivos laborales. Si necesitas apoyo para encontrar opciones, puedes acercarte al Departamento de Estadías e Inserción Laboral para recibir orientación.','alumnos',true,
'["empresa para estadias","cualquier empresa estadias","empresa necesita convenio","estadias convenio empresa","puedo elegir empresa estadias","empresa para practicas profesionales","estadias en cualquier empresa","empresa valida estadias","donde hacer estadias","estadias opciones empresa"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 347
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué pasa si la empresa donde quiero hacer mi estadía no tiene convenio con la UTTT?','No te preocupes. Si la empresa donde deseas realizar tu estadía no cuenta con convenio con la universidad, puedes proporcionar los datos de contacto de la empresa y el Departamento de Estadías e Inserción Laboral se encargará de realizar el proceso de vinculación correspondiente.','alumnos',true,
'["empresa sin convenio","estadias empresa no tiene convenio","convenio empresa uttt","empresa nueva estadias","empresa sin convenio universidad","como hacer convenio empresa","estadias convenio nuevo","empresa no registrada estadias","empresa sin relacion universidad","vinculacion empresa estadias"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 348
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('Si ya estoy trabajando, ¿puedo liberar mi estadía en mi trabajo actual?','Sí. Puedes realizar tu estadía en tu lugar de trabajo siempre y cuando la empresa permita desarrollar un proyecto relacionado con tu perfil profesional y tu carrera académica.','alumnos',true,
'["liberar estadias trabajando","estadias en mi trabajo","puedo hacer estadias donde trabajo","trabajo actual estadias","liberar practicas trabajando","estadias empresa donde trabajo","trabajo y estadias","estadias empleo actual","hacer estadias trabajando","estadias mismo trabajo"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 349
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Puedo hacer mi estadía fuera del estado o en el extranjero?','Sí. Puedes realizar tu estadía fuera del estado o incluso en el extranjero. Es importante mantenerse al pendiente de las convocatorias de movilidad y estadías externas publicadas por la universidad.','alumnos',true,
'["estadias extranjero","estadias fuera del estado","movilidad estadias","estadias internacionales","estadias externas","puedo hacer estadias fuera","estadias otro estado","estadias fuera de mexico","movilidad universidad estadias","estadias internacionales uttt"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 350
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué documentos necesito para iniciar mi estadía?','Si ya cuentas con una empresa para realizar tu estadía, el primer paso es llenar el Formato de Solicitud de Estadías (F-VI-22). Este formato se encuentra disponible en la sección de Vinculación. Sin este documento no es posible iniciar el proceso de estadía.','alumnos',true,
'["documentos estadias","requisitos estadias","formato estadias","f-vi-22","solicitud estadias","papeles estadias","que necesito para estadias","tramite estadias documentos","requisitos practicas profesionales","inicio estadias documentos"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');


-- ID 351
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Quién me va a evaluar durante mi estadía?','Durante tu estadía contarás con dos asesores: un Asesor Académico de la UTTT, quien te apoyará en la parte escolar y seguimiento académico, y un Asesor Industrial dentro de la empresa, quien supervisará tus actividades y desempeño profesional.','alumnos',true,
'["quien evalua estadias","asesor academico estadias","asesor industrial estadias","evaluacion estadias","quien me supervisa estadias","estadias evaluacion empresa","profesor estadias","mentor estadias","asesores estadias","como califican estadias"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 352
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué proyecto debo realizar durante mi estadía?','El proyecto de estadía se define en conjunto con tu Asesor Académico y debe estar relacionado con tu perfil profesional y los objetivos de tu carrera. Tu asesor te orientará sobre los alcances y requisitos necesarios para que el proyecto sea válido.','alumnos',true,
'["proyecto estadias","que hago en estadias","proyecto practicas profesionales","proyecto empresa estadias","tema proyecto estadias","como elegir proyecto estadias","proyecto valido estadias","asesor proyecto estadias","proyecto carrera estadias","estadias proyecto profesional"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 353
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué hago si tengo problemas en la empresa durante mi estadía?','Si tienes problemas durante tu estadía o realizas actividades que no corresponden a tu perfil profesional, debes comunicarte de inmediato con tu Asesor Académico para recibir orientación y apoyo en la solución de la situación con la empresa.','alumnos',true,
'["problemas empresa estadias","empresa no respeta estadias","actividades no corresponden estadias","problemas practicas profesionales","que hago si tengo problemas estadias","empresa abuso estadias","ayuda estadias empresa","conflictos estadias","problemas asesor industrial","estadias problemas trabajo"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 354
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cómo hago mi reporte final de estadía?','El Director de tu carrera realizará una reunión antes del inicio de tu estadía para explicarte la estructura, formato y lineamientos que deberá cumplir tu reporte final o memoria de estadía.','alumnos',true,
'["reporte final estadias","memoria estadias","como hacer memoria estadias","formato reporte estadias","reporte practicas profesionales","estructura memoria estadias","documento final estadias","como entregar memoria","lineamientos estadias","reporte estadias uttt"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 355
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cada cuánto debo entregar avances de mi estadía?','La periodicidad de entrega de avances se establece en conjunto con tu Asesor Académico y tu Asesor Industrial durante la reunión inicial de seguimiento de estadía.','alumnos',true,
'["avances estadias","entrega avances estadias","cada cuanto entrego avances","seguimiento estadias","reportes estadias","calendario estadias","entregas practicas profesionales","avance proyecto estadias","reuniones estadias","entrega memoria estadias"]'::jsonb,
