-- ID 356
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿La estadía tiene calificación?','Sí. Al finalizar tu estadía recibirás una calificación numérica que formará parte de tu historial académico.','alumnos',true,
'["calificacion estadias","estadias cuentan calificacion","nota estadias","estadias promedio","como califican estadias","estadias historial academico","evaluacion final estadias","estadias cuentan promedio","estadias tienen nota","calificacion practicas profesionales"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 357
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿La empresa está obligada a pagarme durante mi estadía?','No. Las empresas no están obligadas a otorgar apoyo económico o beca durante tu estadía. Sin embargo, algunas empresas pueden ofrecer apoyo de transporte, alimentos o una beca económica de manera voluntaria.','alumnos',true,
'["me pagan estadias","beca estadias","empresa paga estadias","pago practicas profesionales","estadias remuneradas","apoyo economico estadias","estadias sueldo","empresa da apoyo estadias","practicas profesionales pagan","estadias apoyo transporte"]'::jsonb,
