-- ID 358
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Debo pagar inscripción aunque esté en estadía?','Sí. Aunque realices tu estadía en una empresa y no asistas regularmente a clases, continúas siendo alumno activo de la universidad y debes cubrir tu cuota de inscripción correspondiente.','alumnos',true,
'["pagar inscripcion estadias","inscripcion durante estadias","debo pagar reinscripcion estadias","estadias cuota universidad","seguir pagando estadias","estadias alumno activo","reinscripcion practicas profesionales","pago cuatrimestre estadias","estadias pago escuela","cuota universidad estadias"]'::jsonb,
