-- ID 359
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Son obligatorias las actividades o talleres?','Sí. Para los alumnos de Técnico Superior Universitario (TSU) es obligatorio cumplir con 240 horas de actividades o talleres, ya que son un requisito indispensable para poder liberar la estadía. Se recomienda llevar un seguimiento constante de tus horas acumuladas en el S.I.G.E. para evitar contratiempos antes de iniciar tu proceso de estadía. Para más información, puedes comunicarte al correo servicios.estudiantiles@uttt.edu.mx o al teléfono 773 732 9100 ext. 456.','alumnos',true,
'["actividades obligatorias","talleres obligatorios","horas taller obligatorias","240 horas obligatorias","actividades para estadia","talleres para estadia","horas actividades universidad","requisito horas taller","horas obligatorias tsu","actividades estudiantes obligatorias","liberar estadia horas","horas talleres uttt","actividades extracurriculares obligatorias","cumplir horas taller","talleres universidad obligatorios","estadias requisito horas","horas para estadia","actividades requisito tsu","horas acumuladas sige","talleres requisito universidad"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');

-- ID 360
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Las actividades o talleres tienen algún costo?','No. Las actividades y talleres dirigidos a la comunidad estudiantil son completamente gratuitos para los alumnos de la universidad. Para más información, puedes comunicarte al correo servicios.estudiantiles@uttt.edu.mx o al teléfono 773 732 9100 ext. 456.','alumnos',true,
'["actividades tienen costo","talleres tienen costo","actividades gratis universidad","talleres gratuitos","horas taller costo","cuanto cuestan talleres","actividades extracurriculares gratis","precio talleres universidad","actividades estudiantiles costo","talleres alumnos gratis","actividades gratuitas uttt","talleres universidad pago","costo actividades estudiantes","talleres cobran","actividades sin costo","horas taller gratis","actividades universidad gratuitas","talleres gratuitos uttt","precio actividades universidad","costo talleres estudiantes"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');


-- ID 361
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿En qué disciplinas puedo participar en actividades o talleres?','La oferta de actividades y talleres puede variar cada cuatrimestre. Generalmente incluye disciplinas deportivas como fútbol, básquetbol, voleibol, taekwondo y ajedrez; así como actividades culturales como danza, rondalla, teatro, mural en gis y apreciación cinematográfica, entre otras opciones. Para conocer la oferta vigente, puedes acercarte a la Subdirección de Apoyo al Desarrollo Integral Estudiantil.','alumnos',true,
'["disciplinas talleres","actividades deportivas universidad","talleres culturales","que talleres hay","deportes universidad","actividades extracurriculares","disciplinas deportivas uttt","talleres estudiantes","clubes universidad","actividades culturales uttt","futbol universidad","taekwondo uttt","danza universidad","voleibol estudiantes","ajedrez universidad","rondalla uttt","teatro universidad","actividades disponibles","que actividades puedo hacer","talleres disponibles uttt"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');  

-- ID 362
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Puedo participar en actividades o talleres aunque no tenga experiencia previa?','Sí. Los talleres y actividades están diseñados tanto para estudiantes principiantes que desean aprender y desarrollar nuevas habilidades, como para alumnos con experiencia previa que buscan mejorar su nivel. Lo importante es tu interés y participación.','alumnos',true,
'["necesito experiencia talleres","puedo entrar sin experiencia","talleres para principiantes","actividades sin experiencia","puedo practicar aunque no sepa","deportes principiantes universidad","talleres alumnos nuevos","actividades para aprender","puedo entrar a talleres desde cero","principiantes actividades universidad","talleres culturales principiantes","aprender deportes universidad","actividades estudiantes principiantes","sin experiencia talleres","puedo unirme talleres","actividades para todos niveles","talleres universidad experiencia","principiantes uttt","puedo participar actividades","niveles talleres universidad"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');


-- ID 363
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cómo benefician las actividades o talleres a mi formación profesional?','Las actividades y talleres ayudan a desarrollar habilidades blandas como trabajo en equipo, liderazgo, disciplina, responsabilidad y comunicación, las cuales son altamente valoradas por las empresas al momento de contratar egresados. Además, contribuyen a tu desarrollo personal, social y profesional.','alumnos',true,
'["beneficios talleres","para que sirven actividades","habilidades blandas universidad","beneficios actividades extracurriculares","liderazgo talleres","trabajo en equipo actividades","disciplina talleres","actividades ayudan carrera","habilidades profesionales estudiantes","beneficios deportes universidad","talleres ayudan trabajo","actividades desarrollo profesional","habilidades blandas estudiantes","ventajas talleres universidad","actividades curriculum","talleres para habilidades","beneficios culturales universidad","actividades ayudan empleo","habilidades empresas buscan","desarrollo personal talleres"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');

