-- ID 384
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué es una certificación de competencias laborales del CONOCER?','Es un reconocimiento oficial otorgado por el CONOCER que valida que una persona cuenta con los conocimientos, habilidades, destrezas y actitudes necesarias para desempeñar una función laboral específica, conforme a un Estándar de Competencia inscrito en el Registro Nacional de Estándares, con validez oficial en México.','alumnos',true,
'["que es certificacion conocer","certificacion competencias laborales","que significa conocer","certificado conocer","competencias laborales mexico","estandar de competencia","certificacion laboral","conocer mexico","certificacion oficial","certificado competencias","para que sirve conocer","validez conocer","certificacion trabajo","competencias laborales conocer","estandar competencia mexico","certificacion profesional","reconocimiento conocer","que es un estandar conocer","certificacion habilidades","certificacion oficial mexico"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');

-- ID 385
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué beneficios tiene obtener una certificación CONOCER?','Obtener una certificación permite demostrar de manera formal la experiencia y capacidad laboral, incrementa las oportunidades de empleo, mejora la competitividad profesional, facilita la movilidad laboral y fortalece el perfil ante empleadores o clientes, ya que las certificaciones CONOCER ahora ya aparecen en la constancia de situación profesional y en la cédula profesional.','alumnos',true,
'["beneficios certificacion conocer","ventajas conocer","para que sirve certificarse","beneficios competencias laborales","certificacion empleo","mejora perfil profesional","certificacion laboral beneficios","competencias laborales ventajas","conocer ayuda trabajo","certificacion profesional mexico","beneficios certificado conocer","certificacion oportunidades empleo","competitividad laboral","ventajas certificacion laboral","conocer curriculum","beneficios estandar competencia","empleo certificacion","certificacion mejora trabajo","conocer profesional","beneficios certificarse"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');

-- ID 386
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Dónde puedo consultar el catálogo de estándares disponibles?','El catálogo oficial se encuentra disponible en el portal del CONOCER, donde puedes buscar por sector, área ocupacional o palabra clave para identificar el estándar que te interesa.','alumnos',true,
'["catalogo conocer","estandares conocer","buscar estandares competencia","portal conocer","catalogo competencias laborales","estandares disponibles conocer","consultar conocer","buscar certificacion conocer","areas conocer","catalogo certificaciones","portal competencias laborales","donde ver estandares","estandares laborales mexico","catalogo oficial conocer","buscar competencia laboral","consultar certificaciones","estandares ocupacionales","catalogo competencias","buscar estandar conocer","sitio conocer"]'::jsonb,
