-- ID 387
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuál es el proceso para certificarse paso a paso?','El proceso generalmente consta de las siguientes etapas: Registro: Solicitud e inscripción con una ECE o Centro de Evaluación. Diagnóstico: Evaluación inicial para identificar el nivel de competencia. Capacitación (opcional): En caso de requerir reforzar conocimientos. Evaluación: Aplicación de instrumentos teóricos, prácticos y evidencias. Dictamen: Emisión del resultado competente o aún no competente. Certificación: En caso de ser competente, se tramita y emite el certificado oficial.','alumnos',true,
'["proceso certificacion","pasos certificarse","como certificarse conocer","tramite certificacion","evaluacion conocer","registro certificacion","diagnostico certificacion","dictamen conocer","emitir certificado conocer","proceso competencias laborales","como obtener certificacion","pasos conocer","evaluacion competencias","tramite conocer","certificacion paso a paso","como funciona conocer","certificacion laboral proceso","registro conocer","proceso estandar competencia","certificacion oficial proceso"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');

-- ID 388
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuánto tiempo dura el proceso de certificación?','El tiempo puede variar dependiendo del estándar de competencia y la disponibilidad del candidato. En promedio, puede tomar desde unos días hasta algunas semanas, considerando el diagnóstico, la evaluación y el proceso de emisión del certificado.','alumnos',true,
'["cuanto tarda certificacion","duracion certificacion","tiempo conocer","dias certificacion","cuanto dura proceso conocer","certificacion tiempo","proceso certificacion tiempo","evaluacion conocer tiempo","emitir certificado tiempo","cuanto tarda conocer","certificacion semanas","duracion competencias laborales","tiempo estandar competencia","cuanto dura conocer","certificacion oficial tiempo","plazo certificacion","certificacion laboral duracion","dias proceso certificacion","tiempo evaluacion conocer","certificado conocer tiempo"]'::jsonb,
