INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Dónde puedo comer dentro de la universidad?','La universidad cuenta con una cafetería dentro de la institución, ubicada entre el edificio UD3 y la Biblioteca. Puedes consultar el croquis oficial en https://www.uttt.edu.mx/Micrositio/croquis/. Además, la universidad cuenta con nuevas mesas y áreas distribuidas en distintos puntos del campus donde puedes consumir tus alimentos libremente y disfrutar del entorno universitario.','alumnos',true,
'["donde puedo comer","cafeteria universidad","donde esta la cafeteria","lugares para comer","comida en la universidad","donde almorzar en la uttt","cafeteria uttt","donde venden comida","hay cafeteria","donde sentarme a comer","areas para comer","mesas para comer","puedo llevar comida","donde esta ud3 cafeteria","cafeteria biblioteca","croquis cafeteria","lugares comida universidad","zonas para comer","comer dentro de la escuela","cafeteria campus"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');





