INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Por qué no puedo entrar al SIGE con el internet de la universidad?','Puede deberse a un error temporal de la plataforma o de conexión dentro de la red universitaria. Si el problema persiste, puedes acudir al área de Sistemas dentro de Rectoría o comunicarte al correo sistemas@uttt.edu.mx indicando tu nombre y situación. También puedes llamar al teléfono 773 732 9100 extensión 237 para recibir apoyo.','alumnos',true,
'["no puedo entrar al sige","sige no funciona","error sige universidad","problema con sige","no abre sige","sige internet universidad","falla sige","porque no carga sige","sige caido","problema plataforma sige","error acceso sige","no puedo iniciar sesion sige","sige con wifi universidad","ayuda sige","contacto sistemas sige","sistemas rectoria","correo sistemas uttt","telefono sistemas uttt","problema red universidad","sige no conecta"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');  


