-- ID 422
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cómo puedo ver cuáles son los docentes que me imparten las asignaturas?','Puedes consultar esta información en tu portal SIGE. Dentro de la sección de horario podrás visualizar los docentes que impartirán cada materia, así como los horarios y días correspondientes.','alumnos',true,
'["como ver mis docentes","quien me da clases","docentes asignaturas","profesores de mis materias","como saber mis maestros","horario sige docentes","docentes sige","maestros de materias","quien imparte mi materia","ver profesores uttt","como ver horario sige","docentes horario","profesores horario","materias y docentes","maestros asignados","quien da la clase","consultar docentes","docentes por materia","ver asignaturas sige","profesores en sige"]'::jsonb,
