-- ID 423
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Si no entiendo un tema bien me ayudas a entenderlo?','¡Claro! Sin embargo, este asistente está enfocado principalmente en responder dudas y temas relacionados con la institución, por lo que no funciona exactamente igual que otras inteligencias artificiales generales como ChatGPT. Una disculpa si en algunos temas externos no puedo profundizar demasiado. Si tienes dificultades para comprender un tema académico, también puedes apoyarte en otras herramientas de inteligencia artificial, consultar videos educativos, bibliografía oficial o pedir ayuda directamente a tus docentes. Si necesitas información institucional, trámites, procesos, servicios o dudas relacionadas con la UTTT, con gusto puedo ayudarte.','alumnos',true,
'["no entiendo un tema","me ayudas a estudiar","explicame un tema","ayuda con tarea","no le entiendo","puedes enseñarme","ayuda academica","me explicas","apoyo con temas","dudas de materias","explicacion tema","me ayudas con una materia","como entender un tema","consejos para estudiar","ayuda escolar","explicar temas","tengo dudas de clase","apoyo estudiante","tema complicado","puedes ayudarme a entender"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');  


