INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Me puedes recomendar videos o documentos para aumentar mi autoaprendizaje?','¡Claro! Sin embargo, este asistente está enfocado principalmente en responder dudas y temas relacionados con la institución, por lo que no funciona exactamente igual que otras inteligencias artificiales enfocadas totalmente al estudio. Una disculpa si en algunos temas académicos no puedo profundizar demasiado. Para fortalecer tu autoaprendizaje puedes apoyarte en videos educativos, documentación oficial, bibliografía, plataformas de aprendizaje y otras herramientas de inteligencia artificial especializadas en estudio. Si necesitas información institucional, trámites, procesos, servicios o dudas relacionadas con la UTTT, con gusto puedo ayudarte.','alumnos',true,
'["videos para estudiar","documentos para aprender","autoaprendizaje","material para estudiar","videos educativos","recomendaciones para estudiar","donde aprender mas","material academico","documentacion estudio","plataformas para estudiar","ia para estudiar","herramientas aprendizaje","como aprender solo","apoyo autoaprendizaje","material educativo","videos de apoyo","documentos educativos","consejos aprendizaje","recursos para estudiar","ayuda para autoaprendizaje"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');   

