INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Dónde encuentro mi horario?','Puedes consultar tu horario directamente en tu portal SIGE, dentro de la sección de horario. Ahí podrás visualizar tus materias, docentes, horarios y aulas correspondientes. Además, en algunos edificios de la universidad se colocan horarios impresos de manera física para consulta de los estudiantes. Te recomendamos verificar correctamente tu grupo y cuatrimestre al momento de revisarlo.','alumnos',true,
