-- ID 426
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuándo inician y terminan las estadías de sexto cuatrimestre?','Las estadías de sexto cuatrimestre generalmente comprenden el periodo correspondiente al cuatrimestre mayo-agosto de cada año. Sin embargo, te recomendamos verificar directamente con tu Dirección de Carrera o área de Estadías, ya que las fechas pueden ajustarse por situaciones académicas o administrativas externas.','alumnos',true,
