-- ID 428
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('Reprobé varias materias, ¿qué puedo hacer?','No te desanimes, reprobar materias no define tu capacidad ni tu futuro académico. Lo más importante es identificar qué situaciones afectaron tu desempeño y comenzar a trabajar en ellas poco a poco. Te recomendamos acercarte con tus docentes, tutor académico o área psicopedagógica para recibir orientación. También puede ayudarte crear horarios de estudio, formar grupos de apoyo, repasar constantemente y apoyarte en materiales educativos o videos relacionados con tus materias. Recuerda que muchos estudiantes pasan por situaciones similares y logran recuperarse con organización y constancia.','alumnos',true,
'["reprobe materias","reprobe tres materias","reprobe 3 materias","reprobe cuatro materias","reprobe 4 materias","reprobe cinco materias","reprobe 5 materias","reprobe muchas materias","me fue mal en la escuela","voy mal en materias","que pasa si reprobe","reprobe el cuatrimestre","no pase materias","estoy reprobando","me siento mal por reprobar","que hago si reprobe","ayuda reprobe materias","recurse materias","voy a recursar","no pase varias materias"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');  

