INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Dónde puedo basarme para hacer mi tesis o reporte de estadía de TSU?','En la página institucional de la universidad, en la siguiente liga: https://uttt.edu.mx/ServiciosDeVinculacion/Alumnos/Es.Estadia.html, dentro de la sección “Formatos de Estadías”, puedes encontrar una guía para realizar tu tesis o reporte de estadía. En caso de tener dudas, te recomendamos acercarte con tu asesor académico para recibir orientación y resolverlas oportunamente.','alumnos',true,
'["como hacer tesis tsu","guia tesis tsu","reporte de estadia","formato tesis","donde ver tesis tsu","como hacer reporte estadia","ejemplo tesis tsu","guia reporte estadia","asesor tesis","formatos estadias","tesis universidad","memoria estadia","como basarme para tesis","reporte estadia uttt","documentos estadia","estructura tesis tsu","ayuda tesis","donde descargar formatos estadia","guia memoria estadia","como hacer mi reporte de estadia"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');

-- ID 430
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuándo puedo hacer el pago de mi cuatrimestre?','Puedes generar y realizar el pago de tu cuatrimestre desde tu portal SIGE, en la sección de “Solicitudes de pago”, donde encontrarás los formatos correspondientes para tu colegiatura. Existen dos formas de pago: pago con tarjeta en línea o imprimir el formato para realizar el pago en los bancos autorizados por la institución. En caso de tener dudas, puedes acercarte al área de Caja ubicada en el edificio UD3, en un horario de 9:00 a.m. a 5:00 p.m.','alumnos',true,
'["pago cuatrimestre","cuando pagar colegiatura","como pagar cuatrimestre","solicitud de pago sige","formatos de pago","pago en linea uttt","pago con tarjeta universidad","imprimir formato de pago","bancos autorizados uttt","donde pagar colegiatura","colegiatura sige","pagar universidad","pago estudiantes","como generar pago","cuota cuatrimestre","pago reinscripcion","area de caja ud3","pago banco universidad","como sacar formato pago","cuando hacer mi pago"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');


-- ID 431
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuántos cuatrimestres debo estudiar en la UTTT?','La duración de los estudios puede variar dependiendo de tu programa educativo y del modelo académico vigente. Actualmente, varios programas de continuidad académica consideran hasta 10 cuatrimestres entre TSU e Ingeniería o Licenciatura. Te recomendamos consultar directamente con tu Dirección de Carrera para conocer la duración específica de tu plan de estudios.','alumnos',true,
'["cuantos cuatrimestres son","duracion carrera","cuantos años estudio","cuanto dura la carrera","cuatrimestres uttt","cuantos tetra son","duracion ingenieria","duracion licenciatura","cuanto dura tsu","cuantos cuatrimestres debo estudiar","plan de estudios","duracion universidad","años de carrera","cuanto tiempo estudio","modelo educativo uttt","cuatrimestres ingenieria","continuidad academica","cuantos ciclos son","duracion programa educativo","cuanto dura estudiar en uttt"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');



