-- ID 434
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Por qué no aparece mi horario en el SIGE?','Esto puede deberse a un problema interno temporal dentro del sistema SIGE. Otra situación común es que, al inicio o término de cuatrimestre, los horarios pueden tardar un poco en actualizarse dentro de la plataforma. Te recomendamos revisar nuevamente más tarde y, si el problema persiste, comunicarte con el área de Sistemas para recibir apoyo.','alumnos',true,
