INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cómo contacto a la Dirección de Carrera?','Para contactar a tu Dirección de Carrera, puedes acudir directamente al edificio correspondiente de tu programa educativo, donde se encuentran las áreas designadas para cada dirección. También te recomendamos acercarte con el personal administrativo de tu edificio para que puedan orientarte y brindarte mayor apoyo.','alumnos',true,
