-- ID 436
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('Siento que no soy bueno para aprender, ¿qué puedo hacer?','Primero que nada, no te desanimes. Tener dificultades para aprender algo no significa que seas “tonto” o que no tengas capacidad. Cada persona aprende a su ritmo y de maneras diferentes. A veces el cansancio, estrés, problemas personales o falta de confianza pueden afectar mucho el aprendizaje. Te recomendamos intentar estudiar en pequeños bloques de tiempo, apoyarte en videos o materiales visuales, hacer preguntas más específicas, practicar constantemente y buscar apoyo con docentes, compañeros o tutorías. También puedes apoyarte en herramientas tecnológicas o inteligencias artificiales para reforzar temas académicos. Lo importante es no rendirte y seguir avanzando poco a poco.','alumnos',true,
'["soy muy burro","soy muy tonto","no puedo aprender","me cuesta aprender","siento que no sirvo","soy malo para estudiar","no entiendo nada","porque soy tan burro","no soy inteligente","me va mal estudiando","no puedo con la escuela","soy muy lento para aprender","siento que no puedo","no entiendo las materias","me siento inutil estudiando","soy malo en la escuela","no puedo concentrarme","me cuesta mucho estudiar","como aprender mejor","ayuda para estudiar","soy un burro","estoy bien tonto","soy demasiado tonto","no puedo con las materias","siento que no doy una","porque no aprendo","me cuesta entender","soy malo aprendiendo","no sirvo para la escuela","como dejar de ser burro"]'::jsonb,
'Cristina Caballero','Jefe de departamento','Subdirección de Servicios Tecnológicos');

