INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Dónde saco una carta de presentación?','Las cartas de presentación generalmente son emitidas por tu Programa Educativo o Dirección de Carrera dentro de las oficinas de tu edificio correspondiente. Normalmente este documento se tramita una vez que concluyes tus materias y ya has tenido contacto o un acuerdo previo con la empresa donde realizarás tu estadía o prácticas. ¡Mucho éxito en tu proceso!','alumnos',true,
