INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Dónde está Control Escolar?','El área de Control Escolar se encuentra dentro del edificio UD3, en la planta baja, al fondo del lado izquierdo cerca de las escaleras. Si tienes dificultades para ubicarla, puedes solicitar apoyo a personal o alumnos cercanos. También puedes consultar el croquis oficial de la universidad en: https://www.uttt.edu.mx/Micrositio/croquis/','alumnos',true,
'["donde esta control escolar","ubicacion control escolar","como llegar a control escolar","oficina control escolar","donde queda control escolar","control escolar ud3","area control escolar","control escolar universidad","croquis control escolar","donde estan servicios escolares","control escolar planta baja","como ubicar control escolar","oficina servicios escolares","donde saco documentos escolares","control escolar cerca escaleras","ubicacion ud3","direccion control escolar","donde preguntar control escolar","servicios escolares uttt","control escolar uttt"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');   


-- ID 440
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿No sé dónde se ubica mi taller o actividad extracurricular?','Si formas parte de algún taller o actividad extracurricular como banda de guerra, fútbol, básquetbol, danza u otra disciplina y no sabes dónde se ubica, te recomendamos ponerte en contacto directamente con el organizador o responsable del taller. También puedes solicitar apoyo en tu Dirección de Carrera para que puedan orientarte y brindarte más información sobre horarios y ubicación.','alumnos',true,
'["donde esta mi taller","no encuentro mi taller","ubicacion taller","donde es banda de guerra","donde entrenan futbol","donde esta basquetbol","donde es danza","taller extracurricular","ubicacion actividades","donde practican banda de guerra","no se donde ir al taller","donde son los talleres","ubicacion futbol","ubicacion danza","ubicacion basquetbol","donde preguntan talleres","actividad extracurricular ubicacion","organizador taller","contacto taller","donde se ubica mi actividad","no encuentro banda de guerra","donde practican los talleres","ubicacion actividad cultural","donde es mi actividad","taller de futbol","taller de danza","taller de basquet","taller cultural","taller deportivo","no se donde esta mi actividad"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');   


-- ID 441
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Me podrías explicar el proceso para seleccionar empresa para las estadías de TSU?','Normalmente, la Dirección de Carrera comparte un catálogo o listado de empresas disponibles para realizar estadías. Lo más recomendable es elegir una empresa que se relacione con tu carrera, que te ayude a desarrollar experiencia profesional y donde el proyecto sea de tu interés. También puedes proponer una empresa externa si cumple con los requisitos necesarios. Una vez que tengas un acuerdo previo con la empresa seleccionada, se inicia el proceso de aceptación y seguimiento correspondiente para formalizar tu estadía. ¡Mucho éxito en esta nueva etapa profesional!','alumnos',true,
'["como elegir empresa estadias","proceso estadias tsu","seleccionar empresa estadias","como buscar empresa estadias","catalogo empresas estadias","empresas para estadia","como funcionan las estadias","proceso aceptacion empresa","donde consigo empresa estadia","como entrar a una empresa","estadias tsu empresa","elegir empresa practicas","empresas vinculacion","puedo proponer empresa","como iniciar estadias","aceptacion estadias","proceso empresa universidad","estadias paso a paso","buscar empresa para estadia","como escoger empresa estadias"]'::jsonb,
'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
